practice_tasks.solution_code:
class CycleList:
    def __init__(self, items, max_yields):
        self.items = items
        self.index = 0
        self.max_yields = max_yields

    def __iter__(self):
        return self

    def __next__(self):
        if self.index >= self.max_yields:
            raise StopIteration
        item = self.items[self.index % len(self.items)]
        self.index += 1
        return item

for item in CycleList(['A', 'B'], max_yields=3):
    print(item)

