class Exhaustible:
    def __init__(self):
        self.val = 2
    def __iter__(self):
        return self
    def __next__(self):
        if self.val == 0: raise StopIteration
        self.val -= 1
        return self.val

iterator = Exhaustible()
print(list(iterator))
print(list(iterator))
